def provide_web_code():
    """
    This script prints the specific HTML and JavaScript 
    needed for your project so you don't have to run files.
    """

    # The HTML part for your button
    html_button = '<button id="galaxyBtn">Click for Galaxy Surprise!</button>'

    # The JavaScript part to make the box pop up
    javascript_logic = """
